# Permission on Demand (POD) — user self-service request workflow
# POD removes the need for standing elevated access

# Step 1: User requests specific permissions for a task via EPM portal
# Step 2: Manager/approver reviews and approves the request
# Step 3: EPM creates a temporary role assignment with the requested actions
# Step 4: EPM automatically revokes the assignment after the time window closes

# Programmatic POD request via Graph API:
$podRequest = @{
    requestedPermissions = @{
        '@odata.type' = '#microsoft.graph.awsPermissionsDefinition'
        authorizationSystemInfo = @{
            authorizationSystemId   = '<aws-account-id>'
            authorizationSystemType = 'aws'
        }
        identityReference = @{ id = '<iam-user-arn>' }
        permissionsDefinitionAction = @{
            '@odata.type' = '#microsoft.graph.awsActionsPermissionsDefinitionAction'
            actions       = @('s3:PutObject', 's3:DeleteObject')
        }
    }
    justification = 'Data migration task #4521 — need write access to S3 for 4 hours'
    scheduleInfo  = @{
        startDateTime = [datetime]::UtcNow.ToString('o')
        expiration    = @{ type = 'afterDuration'; duration = 'PT4H' }
    }
} | ConvertTo-Json -Depth 10

Invoke-MgGraphRequest -Method POST `
  -Uri 'https://graph.microsoft.com/beta/identityGovernance/permissionsManagement/scheduledPermissionsRequests' `
  -Body $podRequest

# Deploy EPM remediation Logic App via Azure CLI
$logicAppDef = @{
    definition = @{
        "$schema" = "https://schema.management.azure.com/providers/Microsoft.Logic/schemas/2016-06-01/workflowdefinition.json#"
        triggers = @{
            Recurrence = @{
                type = 'Recurrence'
                recurrence = @{ frequency = 'Day'; interval = 1 }
            }
        }
        actions = @{
            GetHighPCI = @{
                type = 'Http'
                inputs = @{
                    method = 'GET'
                    uri = 'https://graph.microsoft.com/beta/identityGovernance/permissionsManagement/permissionsAnalyticsAggregation'
                }
            }
        }
    }
} | ConvertTo-Json -Depth 10

az logic workflow create \
  --resource-group rg-epm-automation \
  --name epm-auto-remediate \
  --location eastus \
  --definition $logicAppDef

// Detect permissions re-creep on previously remediated identities
// Assumes a watchlist 'EPMRemediatedIdentities' with columns: identityId, remediationDate
let Remediated = _GetWatchlist('EPMRemediatedIdentities')
    | project identityId = tostring(identityId), remediationDate = todatetime(remediationDate);
EntraPermissionsManagement_CL
| where TimeGenerated > ago(7d)
| where EventType_s == 'PermissionsCreepIndexCalculated'
| extend identityId = IdentityId_s, currentPCI = toint(PCIScore_d)
| join kind=inner Remediated on identityId
| where currentPCI > 70 and TimeGenerated > remediationDate + 1d
| summarize MaxPCI = max(currentPCI), LastSeen = max(TimeGenerated) by identityId
| order by MaxPCI desc

# Cross-cloud PCI summary for a federated identity
$upn = 'devops-lead@contoso.com'
$clouds = @('azure','aws','gcp')
$summary = foreach ($cloud in $clouds) {
    $uri = 'https://graph.microsoft.com/beta/identityGovernance/permissionsManagement/' +
           "permissionsAnalytics/$cloud/findings/" +
           'microsoft.graph.permissionsAnalyticsAggregation?' +
           "`$filter=identity/userPrincipalName eq '$upn'"
    try {
        $r = Invoke-MgGraphRequest -Method GET -Uri $uri
        [pscustomobject]@{
            Cloud = $cloud.ToUpper()
            PCI   = $r.value[0].permissionsCreepIndex.index
            Risk  = $r.value[0].permissionsCreepIndex.riskLevel
        }
    } catch {
        [pscustomobject]@{ Cloud = $cloud.ToUpper(); PCI = 'N/A'; Risk = 'Error' }
    }
}
$summary | Format-Table -AutoSize

$critical = $summary | Where-Object { $_.Risk -eq 'high' }
if ($critical) {
    Write-Warning "Identity $upn has critical PCI in: $($critical.Cloud -join ', ')"
}
